const SUPABASE_URL = 'https://bliybylxjwemgzjvazyc.supabase.co';
const https = require('https');
const result = await new Promise((resolve) => {
  https.get(`${SUPABASE_URL}/storage/v1/object/public/snapshots/daily-brief-facts.json`, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => {
      try { resolve(JSON.parse(data)); } catch (e) { resolve(null); }
    });
  }).on('error', () => resolve(null));
});
if (!result) return [{ json: { error: 'facts_fetch_failed' } }];
return [{ json: result }];

const facts = $input.first().json;
const apiKey = $env.OPENAI_API_KEY;

const prompt = `你是台股盤後分析助理。根據以下事實統計，寫一段繁體中文盤後總結，150字以內，語氣專業精簡，不要加任何前綴或標題：

大盤漲跌：${facts.marketChangePct ?? '—'}%
四象限分布：漲潮${facts.quadrantCounts?.TR ?? 0} 觀望${facts.quadrantCounts?.TL ?? 0} 退潮${facts.quadrantCounts?.BL ?? 0} 輪動${facts.quadrantCounts?.BR ?? 0}
逆勢買超板塊：${(facts.contrarian || []).join('、') || '無'}
昨日買超前三板塊今日表現：${(facts.top3Performance || []).map(t => `${t.sector} ${t.avgChangePct ?? '—'}%`).join('、') || '無'}
異常個股：${(facts.anomalies || []).slice(0, 5).map(a => `${a.name} ${a.net >= 0 ? '+' : ''}${a.net.toFixed(1)}億`).join('、') || '無'}`;

const body = JSON.stringify({
  model: 'gpt-5.4-mini',
  messages: [{ role: 'user', content: prompt }],
  max_tokens: 300,
});

const result = await new Promise((resolve) => {
  const https = require('https');
  const options = {
    hostname: 'api.openai.com',
    path: '/v1/chat/completions',
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
    },
  };
  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => {
      try {
        const json = JSON.parse(data);
        const summary = json.choices?.[0]?.message?.content?.trim();
        resolve(summary ? { ok: true, summary } : { ok: false, error: JSON.stringify(json).slice(0, 300) });
      } catch (e) { resolve({ ok: false, error: e.message }); }
    });
  });
  req.on('error', (e) => resolve({ ok: false, error: e.message }));
  req.write(body);
  req.end();
});

return [{ json: { facts, ...result } }];

const { facts, summary } = $json;
const parts = [summary];
if (facts.contrarian?.length) parts.push(`⚓ 逆勢買超：${facts.contrarian.join('、')}`);
if (facts.anomalies?.length) {
  const list = facts.anomalies.slice(0, 5).map(a => `${a.name}(${a.net >= 0 ? '+' : ''}${a.net.toFixed(1)}億)`).join('、');
  parts.push(`異常個股：${list}`);
}
const text = parts.filter(Boolean).join('<br>');
return [{ json: {
  subject: `📋 ${facts.date ?? ''} 盤後總結`,
  bodyContent: text,
  supabasePayload: { ...facts, summary },
}}];

const { facts } = $json;
const parts = [];
if (facts.contrarian?.length) parts.push(`⚓ 逆勢買超：${facts.contrarian.join('、')}`);
if (facts.anomalies?.length) {
  const list = facts.anomalies.slice(0, 5).map(a => `${a.name}(${a.net >= 0 ? '+' : ''}${a.net.toFixed(1)}億)`).join('、');
  parts.push(`異常個股：${list}`);
}
const text = parts.join('<br>') || '（無特別事項）';
return [{ json: {
  subject: `📋 ${facts.date ?? ''} 盤後總結（AI 總結暫時無法產生，事實版）`,
  bodyContent: text,
  supabasePayload: { ...facts, summary: null },
}}];

const { supabasePayload } = $json;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const https = require('https');
const body = JSON.stringify(supabasePayload);
const result = await new Promise((resolve) => {
  const options = {
    hostname: 'bliybylxjwemgzjvazyc.supabase.co',
    path: '/storage/v1/object/snapshots/daily-brief-facts.json',
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
      'x-upsert': 'true',
    },
  };
  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => resolve({ status: res.statusCode }));
  });
  req.on('error', (e) => resolve({ status: 0, error: e.message }));
  req.write(body);
  req.end();
});
return [{ json: { ...result } }];

